import { useVirtualizer } from '@tanstack/react-virtual';
import clsx from 'clsx';
import { useCallback, useRef } from 'react';

import { ChartLegendItem } from './ChartLegendItem/ChartLegendItem.js';
import {
  legendContent,
  legendGrid,
  virtualizedGrid,
  virtualizedRow,
} from './ChartVirtualizedLegendGrid.sty.js';
import { type ChartLegendOrientation } from '../../../../types/legend.js';
import { useChartLayoutRatio } from '../../../chart-layout/hooks/useChartLayoutRatio.js';
import { useLegendSize } from '../../shared/context/LegendSizeContext.js';
import { CATEGORICAL_LEGEND_CLASS, ITEM_HEIGHT } from '../constants.js';
import { useLegendGridSettings } from '../context/LegendGridSettingsContext.js';
import { type LegendItem } from '../types/legend.js';

interface ChartVirtualizedLegendGridProps {
  /** Items to be represented on the legend grid */
  items: LegendItem[];
  /** orientation of the grid */
  orientation: ChartLegendOrientation;
}

/**
 * Virtualized Grid to represent legend items
 * @param props - Items, legendWidth, gridSettings
 * @returns Virtualized grid with the items
 */
export const ChartVirtualizedLegendGrid = (
  props: ChartVirtualizedLegendGridProps,
) => {
  const { items, orientation } = props;
  const { legendRef } = useChartLayoutRatio();
  const { minItemWidth } = useLegendGridSettings();
  const { width: legendWidth } = useLegendSize();

  const seriesCount = items.length;
  const nrOfColumns = Math.max(Math.floor(legendWidth / minItemWidth), 1);
  const nrOfRows = Math.ceil(seriesCount / nrOfColumns);

  const parentRef = useRef<HTMLDivElement>(null);

  const virtualizer = useVirtualizer({
    count: nrOfRows,
    getScrollElement: () => parentRef.current,
    estimateSize: useCallback(() => ITEM_HEIGHT.value, []),
    overscan: 0,
  });

  return (
    <div
      ref={parentRef}
      className={`${legendContent({
        layout: orientation,
      })} chart-legend-grid-content`}
    >
      <div
        ref={legendRef}
        data-testid="chart-legend-grid-virtual"
        className={clsx(virtualizedGrid, CATEGORICAL_LEGEND_CLASS)}
        style={{
          height: virtualizer.getTotalSize(),
        }}
      >
        {virtualizer.getVirtualItems().map((virtualRow) => {
          const rowStartIndex = virtualRow.index * nrOfColumns;
          const rowEndIndex = rowStartIndex + nrOfColumns;
          const gridTemplateColumns = `repeat(${nrOfColumns}, 1fr)`;

          return (
            <div
              key={virtualRow.index}
              className={virtualizedRow}
              style={{
                height: `${virtualRow.size}px`,
                transform: `translateY(${virtualRow.start}px)`,
              }}
            >
              <div
                className={legendGrid({ layout: orientation })}
                style={{ gridTemplateColumns }}
              >
                {items.slice(rowStartIndex, rowEndIndex).map((item) => (
                  <ChartLegendItem
                    item={item}
                    key={item.id}
                    numberOfItems={items.length}
                  />
                ))}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};
